import { createApiKeyAuth } from './task15';

describe('createApiKeyAuth', () => {
  it('allows valid key', () => {
    const auth = createApiKeyAuth('secret123');
    let called = false;
    const req = { headers: { 'x-api-key': 'secret123' } } as any;
    const res = {} as any;
    auth(req, res, () => { called = true; });
    expect(called).toBe(true);
  });

  it('rejects invalid key', () => {
    const auth = createApiKeyAuth('secret123');
    let called = false;
    const req = { headers: { 'x-api-key': 'wrong' } } as any;
    const res = { status: () => ({ json: () => {} }) } as any;
    auth(req, res, () => { called = true; });
    expect(called).toBe(false);
  });

  it('rejects missing key', () => {
    const auth = createApiKeyAuth('secret123');
    let called = false;
    const req = { headers: {} } as any;
    const res = { status: () => ({ json: () => {} }) } as any;
    auth(req, res, () => { called = true; });
    expect(called).toBe(false);
  });
});
